@app.route('/')
def index():
    if session.get('authenticated') and not session.get('mfa_pending'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login_page'))


@app.route('/login', methods=['GET', 'POST'])
def login_page():
    if request.method == 'GET':
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required.'), 400

    if is_account_locked(username):
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Account is temporarily locked due to too many failed attempts. Try again later.'
        ), 429

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        record_failed_attempt(username)
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.'), 401

    reset_login_attempts(username)

    session.regenerate = True
    session['username'] = username
    session['roles'] = user['roles']

    if user.get('mfa_enabled') and user.get('mfa_secret'):
        # MFA is required - do not grant full access yet
        session['mfa_pending'] = True
        session['authenticated'] = False
        return redirect(url_for('mfa_page'))
    else:
        # No MFA - grant access immediately
        session['authenticated'] = True
        session['mfa_pending'] = False
        session.permanent = True
        return redirect(url_for('dashboard'))


@app.route('/mfa', methods=['GET'])
def mfa_page():
    if not session.get('username') or not session.get('mfa_pending'):
        return redirect(url_for('login_page'))
    return render_template_string(MFA_TEMPLATE, error=None)


@app.route('/mfa/verify', methods=['POST'])
def mfa_verify():
    if not session.get('username') or not session.get('mfa_pending'):
        return redirect(url_for('login_page'))

    username = session['username']
    otp_code = request.form.get('otp', '').strip()

    if not otp_code or not otp_code.isdigit() or len(otp_code) != 6:
        return render_template_string(MFA_TEMPLATE, error='Please enter a valid 6-digit code.'), 400

    user = users_db.get(username)
    if not user:
        session.clear()
        return redirect(url_for('login_page'))

    totp = pyotp.TOTP(user['mfa_secret'])
    # valid_window=1 allows for slight time drift (±30 seconds)
    if not totp.verify(otp_code, valid_window=1):
        record_failed_attempt(username)
        if is_account_locked(username):
            session.clear()
            return render_template_string(
                LOGIN_TEMPLATE,
                error='Account locked due to too many failed attempts.'
            ), 429
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP code. Please try again.'), 401

    reset_login_attempts(username)

    # Regenerate session to prevent fixation
    old_data = dict(session)
    session.clear()
    session.update(old_data)
    session['authenticated'] = True
    session['mfa_pending'] = False
    session.permanent = True

    return redirect(url_for('dashboard'))


@app.route('/dashboard')
@login_required
def dashboard():
    username = session.get('username')
    user = users_db.get(username, {})
    return render_template_string(
        DASHBOARD_TEMPLATE,
        username=username,
        mfa_enabled=user.get('mfa_enabled', False)
    )


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login_page'))


