# --- MFA Management Endpoints ---

@app.route('/mfa/setup', methods=['POST'])
@login_required
def mfa_setup():
    """Enable MFA for the current user."""
    username = session.get('username')
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled'}), 400

    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user.get('email', username),
        issuer_name='SecureApp'
    )

    # Store secret but don't enable MFA until verified
    user['mfa_secret_pending'] = secret

    return jsonify({
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'message': 'Scan the QR code or enter the secret in your authenticator app, then confirm with /mfa/confirm.'
    })


@app.route('/mfa/confirm', methods=['POST'])
@login_required
def mfa_confirm():
    """Confirm MFA setup by verifying an OTP code."""
    username = session.get('username')
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    pending_secret = user.get('mfa_secret_pending')
    if not pending_secret:
        return jsonify({'error': 'No pending MFA setup. Call /mfa/setup first.'}), 400

    data = request.get_json() or {}
    otp_code = str(data.get('otp', '')).strip()

    if not otp_code or not otp_code.isdigit() or len(otp_code) != 6:
        return jsonify({'error': 'Valid 6-digit OTP required'}), 400

    totp = pyotp.TOTP(pending_secret)
    if not totp.verify(otp_code, valid_window=1):
        return jsonify({'error': 'Invalid OTP. Please try again.'}), 401

    user['mfa_secret'] = pending_secret
    user['mfa_enabled'] = True
    del user['mfa_secret_pending']

    return jsonify({'message': 'MFA has been enabled successfully.'})


@app.route('/mfa/disable', methods=['POST'])
@login_required
def mfa_disable():
    """Disable MFA for the current user. Requires current password confirmation."""
    username = session.get('username')
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is not enabled'}), 400

    data = request.get_json() or {}
    password = data.get('password', '')

    if not password or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Password confirmation required'}), 401

    user['mfa_enabled'] = False
    user['mfa_secret'] = None

    return jsonify({'message': 'MFA has been disabled.'})


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


